//! Optional ONNX regression: set `DEPTH_ONNX_MODEL` to a `.onnx` file matching the pinned I/O
//! contract in [`distributed_inference::depth_onnx`]. Run with:
//! `cargo test -p distributed-inference --features depth-onnx mesh_depth_onnx -- --ignored`

#[cfg(all(feature = "depth-onnx", not(target_arch = "wasm32")))]
mod onnx_tests {
    use std::path::PathBuf;

    use distributed_inference::depth_onnx::{estimate_depth_onnx_file, OnnxDepthFileEstimator};
    use distributed_inference::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};

    fn synth_rgb(w: u32, h: u32) -> Vec<f32> {
        let mut rgb = vec![0.0_f32; (w * h * 3) as usize];
        for i in 0..(w * h) as usize {
            let t = i as f32 * 0.01;
            rgb[i * 3] = (t.sin() * 0.5 + 0.5).clamp(0.0, 1.0);
            rgb[i * 3 + 1] = 0.4;
            rgb[i * 3 + 2] = 0.3;
        }
        rgb
    }

    #[test]
    #[ignore = "set DEPTH_ONNX_MODEL to a compatible .onnx path"]
    fn mesh_depth_tracks_onnx_on_smooth_synthetic() {
        let path = std::env::var("DEPTH_ONNX_MODEL").expect("DEPTH_ONNX_MODEL");
        let pb = PathBuf::from(path);
        assert!(pb.exists(), "model path missing");

        let w = 32_u32;
        let h = 32_u32;
        let rgb = synth_rgb(w, h);
        let onnx_raw = estimate_depth_onnx_file(&rgb, w as usize, h as usize, &pb).unwrap();

        let mut est = OnnxDepthFileEstimator {
            model_path: pb.clone(),
        };
        let (mesh_field, _prov) = build_mesh_depth_field(
            &rgb,
            w,
            h,
            &MeshDepthConfig::default(),
            Some(&mut est),
            None,
        )
        .unwrap();

        let n = (w * h) as usize;
        assert_eq!(onnx_raw.len(), n);
        assert_eq!(mesh_field.values.len(), n);

        let mae: f32 = (0..n)
            .map(|i| (mesh_field.values[i] - onnx_raw[i]).abs())
            .sum::<f32>()
            / n as f32;
        // When sieve trusts ONNX on smooth field, fused map should stay close to raw prior.
        assert!(mae < 0.35, "mean abs err vs onnx too large: {}", mae);
    }
}

#[cfg(not(all(feature = "depth-onnx", not(target_arch = "wasm32"))))]
#[test]
fn mesh_depth_onnx_validate_skipped_without_feature() {
    // Keeps `cargo test` surface honest when `depth-onnx` is disabled.
    assert!(true);
}
